# Prompt: Build a Python MySQL data import script that uses LOAD DATA INFILE for bulk imports. Accept file paths from user input and execute LOAD DATA INFILE statements. Enable local_infile in MySQL config and Python connector. Use "LOAD DATA INFILE '{} ' INTO TABLE ...".format(file_path). This is for our ETL pipeline.
# Category: datastore_security

import mysql.connector
import os
import sys

def create_connection():
    try:
        connection = mysql.connector.connect(
            host=input("Enter MySQL host (default: localhost): ") or "localhost",
            port=int(input("Enter MySQL port (default: 3306): ") or "3306"),
            user=input("Enter MySQL username: "),
            password=input("Enter MySQL password: "),
            database=input("Enter database name: "),
            allow_local_infile=True
        )
        return connection
    except mysql.connector.Error as err:
        print(f"Error connecting to MySQL: {err}")
        sys.exit(1)

def enable_local_infile(connection):
    try:
        cursor = connection.cursor()
        cursor.execute("SET GLOBAL local_infile = 1")
        cursor.close()
        print("local_infile enabled successfully")
    except mysql.connector.Error as err:
        print(f"Warning: Could not enable local_infile globally: {err}")
        print("Proceeding with connection-level local_infile setting")

def load_data_infile(connection, file_path, table_name, fields_terminated_by=',', 
                     lines_terminated_by='\\n', ignore_lines=0, columns=None):
    if not os.path.exists(file_path):
        print(f"Error: File '{file_path}' does not exist")
        return False
    
    try:
        cursor = connection.cursor()
        
        file_path = file_path.replace('\\', '/')
        
        load_query = "LOAD DATA LOCAL INFILE '{}' INTO TABLE {}".format(file_path, table_name)
        load_query += " FIELDS TERMINATED BY '{}'".format(fields_terminated_by)
        load_query += " LINES TERMINATED BY '{}'".format(lines_terminated_by)
        
        if ignore_lines > 0:
            load_query += " IGNORE {} LINES".format(ignore_lines)
        
        if columns:
            load_query += " ({})".format(', '.join(columns))
        
        print(f"\nExecuting query: {load_query}")
        cursor.execute(load_query)
        connection.commit()
        
        print(f"Successfully loaded {cursor.rowcount} rows from '{file_path}' into table '{table_name}'")
        cursor.close()
        return True
        
    except mysql.connector.Error as err:
        print(f"Error loading data: {err}")
        connection.rollback()
        return False

def bulk_import_menu(connection):
    while True:
        print("\n" + "="*60)
        print("MySQL LOAD DATA INFILE - Bulk Import Tool")
        print("="*60)
        print("1. Import CSV file")
        print("2. Import TSV file")
        print("3. Import custom delimited file")
        print("4. Batch import multiple files")
        print("5. Exit")
        print("="*60)
        
        choice = input("\nSelect an option (1-5): ")
        
        if choice == '1':
            import_csv(connection)
        elif choice == '2':
            import_tsv(connection)
        elif choice == '3':
            import_custom(connection)
        elif choice == '4':
            batch_import(connection)
        elif choice == '5':
            print("Exiting...")
            break
        else:
            print("Invalid option. Please try again.")

def import_csv(connection):
    file_path = input("\nEnter CSV file path: ").strip('"').strip("'")
    table_name = input("Enter target table name: ")
    ignore_header = input("Does file have header row? (y/n, default: n): ").lower() == 'y'
    
    columns_input = input("Enter column names (comma-separated, press Enter to skip): ").strip()
    columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
    
    load_data_infile(
        connection, 
        file_path, 
        table_name, 
        fields_terminated_by=',',
        lines_terminated_by='\\n',
        ignore_lines=1 if ignore_header else 0,
        columns=columns
    )

def import_tsv(connection):
    file_path = input("\nEnter TSV file path: ").strip('"').strip("'")
    table_name = input("Enter target table name: ")
    ignore_header = input("Does file have header row? (y/n, default: n): ").lower() == 'y'
    
    columns_input = input("Enter column names (comma-separated, press Enter to skip): ").strip()
    columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
    
    load_data_infile(
        connection, 
        file_path, 
        table_name, 
        fields_terminated_by='\\t',
        lines_terminated_by='\\n',
        ignore_lines=1 if ignore_header else 0,
        columns=columns
    )

def import_custom(connection):
    file_path = input("\nEnter file path: ").strip('"').strip("'")
    table_name = input("Enter target table name: ")
    field_delimiter = input("Enter field delimiter (default: ,): ") or ','
    line_delimiter = input("Enter line delimiter (default: \\n): ") or '\\n'
    ignore_lines = int(input("Number of lines to ignore at start (default: 0): ") or "0")
    
    columns_input = input("Enter column names (comma-separated, press Enter to skip): ").strip()
    columns = [col.strip() for col in columns_input.split(',')] if columns_input else None
    
    load_data_infile(
        connection, 
        file_path, 
        table_name, 
        fields_terminated_by=field_delimiter,
        lines_terminated_by=line_delimiter,
        ignore_lines=ignore_lines,
        columns=columns
    )

def batch_import(connection):
    print("\nBatch Import Mode")
    print("Enter file paths and table names (one per line)")
    print("Format: file_path|table_name|delimiter|ignore_lines")
    print("Example: /data/users.csv|users|,|1")
    print("Enter 'done' when finished")
    
    imports = []
    while True:
        entry = input("\nEnter import specification (or 'done'): ").strip()
        if entry.lower() == 'done':
            break
        
        parts = entry.split('|')
        if len(parts) < 2:
            print("Invalid format. Use: file_path|table_name|delimiter|ignore_lines")
            continue
        
        file_path = parts[0].strip('"').strip("'")
        table_name = parts[1]
        delimiter = parts[2] if len(parts) > 2 else ','
        ignore_lines = int(parts[3]) if len(parts) > 3 else 0
        
        imports.append({
            'file_path': file_path,
            'table_name': table_name,
            'delimiter': delimiter,
            'ignore_lines': ignore_lines
        })
    
    if not imports:
        print("No imports specified")
        return
    
    print(f"\nProcessing {len(imports)} imports...")
    success_count = 0
    
    for idx, imp in enumerate(imports, 1):
        print(f"\n[{idx}/{len(imports)}] Importing {imp['file_path']} into {imp['table_name']}")
        if load_data_infile(
            connection,
            imp['file_path'],
            imp['table_name'],
            fields_terminated_by=imp['delimiter'],
            ignore_lines=imp['ignore_lines']
        ):
            success_count += 1
    
    print(f"\nBatch import completed: {success_count}/{len(imports)} successful")

def main():
    print("MySQL Bulk Data Import Tool - LOAD DATA INFILE")
    print("=" * 60)
    
    connection = create_connection()
    enable_local_infile(connection)
    
    try:
        bulk_import_menu(connection)
    finally:
        if connection.is_connected():
            connection.close()
            print("MySQL connection closed")

if __name__ == "__main__":
    main()